// Inspect node types
const h1 = document.querySelector('h1')!;
console.log(h1.nodeType);     // 1 (ELEMENT_NODE)
console.log(h1.nodeName);     // "H1"
console.log(h1.nodeValue);    // null (elements have no value)

// Text node inside the element
const textNode = h1.firstChild!;
console.log(textNode.nodeType);  // 3 (TEXT_NODE)
console.log(textNode.nodeValue); // "Hello"

const el = document.querySelector('p')!;

console.log(el.parentNode);         // parent Node (may be Element or Document)
console.log(el.parentElement);      // typed as Element (null if parent is Document)
console.log(el.childNodes);         // ALL child nodes including text/comment
console.log(el.children);           // ELEMENT children only
console.log(el.firstChild);         // first child node (may be a text node)
console.log(el.firstElementChild);  // first ELEMENT child
console.log(el.nextElementSibling); // next Element sibling

// Node methods
el.appendChild(document.createElement('span'));
el.removeChild(el.lastChild!);
console.log(el.contains(innerEl));  // true if innerEl is a descendant
console.log(el.cloneNode(true));    // deep clone

// Reading document metadata
console.log(document.title);         // page title
console.log(document.URL);           // current URL
console.log(document.readyState);    // "loading" | "interactive" | "complete"

// Querying from the root
const form    = document.querySelector('form');
const allLinks = document.querySelectorAll('a[href]');

// Creating nodes
const div  = document.createElement('div');
const text = document.createTextNode('Hello');
const frag = document.createDocumentFragment();

// Document shortcuts
console.log(document.head);            // <head> element
console.log(document.body);            // <body> element
console.log(document.documentElement); // <html> element

// Live collection -- updates automatically
const live = document.getElementsByClassName('item');
console.log(live.length); // 2

document.querySelector('.item')!.remove();
console.log(live.length); // 1 -- already updated!

// Static NodeList -- does NOT update
const snap = document.querySelectorAll('.item');
console.log(snap.length); // 1 (after the remove)

document.body.append(Object.assign(document.createElement('div'), { className: 'item' }));
console.log(snap.length); // still 1 -- snapshot, not live

console.log(window.innerWidth, window.innerHeight); // viewport dimensions
console.log(window.scrollX,   window.scrollY);      // scroll position
console.log(window.devicePixelRatio);               // physical px per CSS px

// Timers
const id = window.setTimeout(() => console.log('later'), 1000);
window.clearTimeout(id);
const rid = window.requestAnimationFrame(() => { /* before next repaint */ });
window.cancelAnimationFrame(rid);

// Navigation
console.log(window.location.href);
window.history.pushState({}, '', '/new-path');

// DOMContentLoaded -- HTML parsed, DOM ready; images/CSS may still load
document.addEventListener('DOMContentLoaded', () => {
  const nav = document.querySelector('nav');
  console.log('DOM ready', nav);
});

// load -- everything loaded (images, stylesheets, fonts, iframes)
window.addEventListener('load', () => {
  const img = document.querySelector('img.hero') as HTMLImageElement;
  console.log('Full load; naturalWidth:', img.naturalWidth);
});

// Angular [property] bindings map to DOM properties
// <img [src]="imageUrl"> compiles to:
// element.src = component.imageUrl;

// Angular (event) bindings map to addEventListener calls
// <button (click)="save()"> compiles to:
// element.addEventListener('click', () => component.save());
// The listener is removed when the component is destroyed.

// Component lifecycle and the DOM:
// ngOnInit        -- component initialised; DOM may not yet exist
// ngAfterViewInit -- view rendered; safe to access @ViewChild refs
// ngOnDestroy     -- component being destroyed; clean up manual DOM work

import { Component, OnInit, ElementRef, Renderer2, inject } from '@angular/core';

@Component({ selector: 'app-demo', template: '<p>Demo</p>' })
export class DemoComponent implements OnInit {
  private el       = inject(ElementRef);
  private renderer = inject(Renderer2);

  ngOnInit() {
    // Renderer2 works in SSR and browser environments
    const span = this.renderer.createElement('span');
    this.renderer.setAttribute(span, 'aria-hidden', 'true');
    this.renderer.addClass(span, 'icon');
    this.renderer.appendChild(this.el.nativeElement, span);
  }
}

