// Watch for changes in a container
const container = document.querySelector('.dynamic-content')!;

const observer = new MutationObserver((mutations) => {
  for (const mutation of mutations) {
    if (mutation.type === 'childList') {
      mutation.addedNodes.forEach(node => {
        console.log('Added:', node);
      });
      mutation.removedNodes.forEach(node => {
        console.log('Removed:', node);
      });
    }
    if (mutation.type === 'attributes') {
      console.log(
        `Attr ${mutation.attributeName} changed on`,
        mutation.target
      );
    }
  }
});

observer.observe(container, {
  childList:  true,       // watch child additions/removals
  subtree:    true,       // include all descendants
  attributes: true,       // watch attribute changes
  attributeFilter: ['class', 'data-state'], // only these attributes
  characterData: false,   // skip text content changes
});

// Disconnect when done (e.g. in ngOnDestroy)
observer.disconnect();

