// Attaching a shadow root to a custom element
const host = document.querySelector('.card')!;
const shadow = host.attachShadow({ mode: 'open' }); // 'closed' = no external access

const style = document.createElement('style');
style.textContent = 'p { color: #3b82f6; font-weight: bold; }';

const p = document.createElement('p');
p.textContent = 'Shadow DOM content';

shadow.append(style, p);

// External CSS does NOT affect the <p> above
// document.querySelector('.card p') returns null -- hidden from the main tree

// Angular ViewEncapsulation settings:
// ViewEncapsulation.Emulated (default) -- scoped styles via attribute selectors
// ViewEncapsulation.ShadowDom          -- real Shadow DOM
// ViewEncapsulation.None               -- global styles (no encapsulation)

// Layout thrashing -- bad: alternating reads and writes force multiple reflows
for (const el of elements) {
  el.style.width = el.offsetWidth + 10 + 'px'; // read then write in same frame
}

// Better: batch all reads first, then all writes
const widths = elements.map(el => el.offsetWidth); // all reads
elements.forEach((el, i) => el.style.width = widths[i] + 10 + 'px'); // all writes

// Best for animation: use requestAnimationFrame
function animate() {
  requestAnimationFrame(() => {
    // reads and writes in the same rAF callback are safe
    elements.forEach(el => {
      el.style.transform = `translateX(${el.offsetLeft + 1}px)`;
    });
    animate();
  });
}

